package projet.ensa.ma.stars.service;

import projet.ensa.ma.stars.beans.Star;
import projet.ensa.ma.stars.dao.IDao;

import java.util.ArrayList;
import java.util.List;

public class StarService implements IDao<Star> {

    private final List<Star> stars;
    private static StarService instance;

    private StarService() {
        stars = new ArrayList<>();
        seed();
    }

    public static StarService getInstance() {
        if (instance == null) instance = new StarService();
        return instance;
    }

    private void seed() {
        stars.add(new Star(
                "Emma Watson",
                "https://upload.wikimedia.org/wikipedia/commons/7/7f/Emma_Watson_2013.jpg",

                4.5f
        ));
        stars.add(new Star(
                "Tom Cruise",
                "https://upload.wikimedia.org/wikipedia/commons/3/33/Tom_Cruise_by_Gage_Skidmore_2.jpg",
                4.2f
        ));
        stars.add(new Star(
                "Brad Pitt",
                "https://upload.wikimedia.org/wikipedia/commons/4/4c/Brad_Pitt_2019_by_Glenn_Francis.jpg",
                4.1f
        ));
        stars.add(new Star(
                "Leonardo DiCaprio",
                "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRYNBkZRv78eCb0LYCa6NRRcon5M9ltULYbrw&s",
                4.5f
        ));
        stars.add(new Star(
                "Scarlett Johansson",
                "data:image/jpeg;base64,",
                4.6f
        ));
        stars.add(new Star(
                "Denzel Washington",
                "data:image/jpeg;base64,",
                4.7f
        ));
    }

    @Override public boolean create(Star o)  { return stars.add(o); }

    @Override
    public boolean update(Star o) {
        for (Star s : stars) {
            if (s.getId() == o.getId()) {
                s.setName(o.getName());
                s.setImg(o.getImg());
                s.setRating(o.getRating());
                return true;
            }
        }
        return false;
    }

    @Override
    public boolean delete(Star o) { return stars.remove(o); }

    @Override
    public Star findById(int id) {
        for (Star s : stars) if (s.getId() == id) return s;
        return null;
    }

    @Override
    public List<Star> findAll() { return stars; }
}